export type GlossaryTerm = {
  slug: string;
  term: string;
  definition: string;
  whyItMatters: string;
  commonMisconceptions: string;
  relatedTerms: string[];
};

export const glossaryTerms: GlossaryTerm[] = [
  { slug: "masking", term: "Masking", definition: "Masking is the practice of hiding or suppressing autistic traits to fit into neurotypical social environments. It includes forcing eye contact, copying others' body language, scripting conversations in advance, suppressing stims, and performing emotions that feel expected rather than genuine.", whyItMatters: "Masking takes significant energy and is strongly linked to autistic burnout, anxiety, depression, and delayed diagnosis — especially in women and gender-diverse people.", commonMisconceptions: "Masking is not the same as improving social skills. It is not a neutral coping strategy. It is effortful concealment that comes at a psychological cost.", relatedTerms: ["camouflaging", "autistic-burnout", "unmasking", "late-diagnosis"] },
  { slug: "stimming", term: "Stimming", definition: "Stimming — short for self-stimulatory behavior — refers to repetitive movements, sounds, or sensory input that help regulate the nervous system. Common stims include hand-flapping, rocking, humming, spinning, chewing, or repeating phrases.", whyItMatters: "Stimming serves a genuine neurological function: it helps autistic people manage sensory input, regulate emotions, and communicate. Suppressing stims is harmful and linked to increased anxiety.", commonMisconceptions: "Stimming is not a symptom to eliminate. It is not inherently disruptive. Many non-autistic people stim too — leg-bouncing, hair-twirling, pen-clicking — but autistic stims are more visible and more frequently targeted for suppression.", relatedTerms: ["sensory-processing", "autistic-burnout", "masking"] },
  { slug: "echolalia", term: "Echolalia", definition: "Echolalia is the repetition of words, phrases, or sounds heard from others or from media. Immediate echolalia repeats something just heard. Delayed echolalia repeats something heard in the past — sometimes from TV, books, or prior conversations.", whyItMatters: "Echolalia is a form of communication, not meaningless repetition. Many autistic people use echolalic phrases intentionally to communicate needs, regulate emotions, or express meaning. Treating it as a behavior to eliminate can shut down communication pathways.", commonMisconceptions: "Echolalia does not indicate lack of understanding. Many autistic people who use echolalia understand far more than they can express. It is a feature of language processing, not evidence of intellectual limitation.", relatedTerms: ["scripts", "perseveration", "aac", "communication-aac"] },
  { slug: "scripts", term: "Scripts", definition: "Scripts are memorized phrases or dialogue that autistic people use in social situations. Scripts may come from movies, TV shows, books, or past conversations. They provide predictable language for unpredictable social situations.", whyItMatters: "Scripting is a legitimate communication strategy. It reduces the cognitive load of generating novel language in real time and allows participation in social situations that would otherwise be overwhelming.", commonMisconceptions: "Using scripts does not mean someone is not communicating authentically. Scripts are tools — just like any other communication strategy. They often carry real meaning that the speaker is conveying through borrowed language.", relatedTerms: ["echolalia", "masking", "aac"] },
  { slug: "perseveration", term: "Perseveration", definition: "Perseveration refers to the repetition of a particular response, thought, or behavior even when it is no longer relevant or appropriate. In autism, it often refers to returning repeatedly to a topic, activity, or question.", whyItMatters: "Perseveration can reflect anxiety, a genuine special interest, or difficulty with cognitive flexibility. Understanding the function helps caregivers and educators respond appropriately rather than simply redirecting.", commonMisconceptions: "Perseveration is not stubbornness. It is not willful ignoring of social cues. It often reflects a nervous system that is processing or regulating through repetition.", relatedTerms: ["special-interest", "executive-function", "monotropism"] },
  { slug: "special-interest", term: "Special Interest", definition: "A special interest is a topic, activity, or subject that an autistic person engages with at an intense, focused level. Special interests are often highly detailed, bring significant joy and comfort, and can become areas of deep expertise.", whyItMatters: "Special interests are a source of identity, joy, regulation, and connection. They are not symptoms to manage. Many autistic people build careers, friendships, and meaning around their special interests.", commonMisconceptions: "Special interests are often dismissed as obsessions or fixations. They are not pathological. Sharing a special interest is one of the primary ways many autistic people connect with others.", relatedTerms: ["monotropism", "hyperfocus", "perseveration"] },
  { slug: "monotropism", term: "Monotropism", definition: "Monotropism is a theory of autism that describes how autistic people tend to focus their attention and interests intensely on fewer things at once, rather than spreading attention broadly. Developed by Dinah Murray, Mike Lesser, and Wenn Lawson.", whyItMatters: "Monotropism helps explain many autistic experiences: the depth of special interests, difficulty switching tasks, sensory sensitivity, and the cost of social interaction. It frames autism as a different attentional style rather than a collection of deficits.", commonMisconceptions: "Monotropism is not the same as inflexibility. It is a different way of allocating cognitive resources — one with real strengths as well as challenges.", relatedTerms: ["special-interest", "hyperfocus", "executive-function"] },
  { slug: "hyperfocus", term: "Hyperfocus", definition: "Hyperfocus is a state of intense concentration on a task or topic, during which external distractions fade and time awareness diminishes. It is common in autism and ADHD, though the experience may differ between the two.", whyItMatters: "Hyperfocus can produce remarkable work and deep engagement. It is also associated with difficulty disengaging — transitioning out of hyperfocus can be physically uncomfortable.", commonMisconceptions: "Hyperfocus is not the same as attention deficit. Many autistic people can hyperfocus extensively on preferred topics while struggling to attend to non-preferred tasks — both reflect different attentional regulation, not global attention failure.", relatedTerms: ["monotropism", "special-interest", "executive-function"] },
  { slug: "meltdown", term: "Meltdown", definition: "A meltdown is an involuntary neurological response to sensory, emotional, or cognitive overwhelm. During a meltdown, the autistic person may cry, scream, hit, bite themselves, or become unable to speak. They are not in control and cannot simply stop.", whyItMatters: "Meltdowns are neurological events, not behavioral choices. Responding with punishment or restraint is harmful and ineffective. The appropriate response is safety, reduced stimulation, and patience.", commonMisconceptions: "Meltdowns are not tantrums. They are not manipulation. They occur even without an audience. They are not a sign of bad parenting. They are a sign of an overwhelmed nervous system.", relatedTerms: ["shutdown", "sensory-overload", "stimming", "autistic-burnout"] },
  { slug: "shutdown", term: "Shutdown", definition: "A shutdown is a response to overwhelm in which the autistic person withdraws, becomes unresponsive, or loses the ability to speak or move effectively. It is the nervous system's protective response to excessive demands.", whyItMatters: "Shutdowns are often invisible compared to meltdowns — they can be mistaken for compliance or indifference. They indicate significant distress and require the same compassionate response as meltdowns.", commonMisconceptions: "A shutdown is not the same as ignoring someone. It is not a power play. A shutting-down person is not fine — they are dysregulated and need space, not increased demands.", relatedTerms: ["meltdown", "sensory-overload", "autistic-burnout"] },
  { slug: "autistic-burnout", term: "Autistic Burnout", definition: "Autistic burnout is a state of profound physical, mental, and emotional exhaustion caused by sustained masking, chronic stress, and long-term sensory overload. It is distinct from occupational burnout and often involves loss of previously held skills.", whyItMatters: "Burnout can last months or years. It can cause significant regression in functioning. It is preventable — by reducing masking demands and building in recovery time.", commonMisconceptions: "Autistic burnout is not laziness. It is not depression, though they can co-occur. It cannot be resolved by pushing through. The primary treatment is rest, reduced demands, and removing the requirement to mask.", relatedTerms: ["masking", "shutdown", "meltdown", "unmasking"] },
  { slug: "unmasking", term: "Unmasking", definition: "Unmasking is the process of gradually reducing or stopping the concealment of autistic traits. It can be deliberate or happen during burnout when masking capacity collapses. Many autistic people find unmasking essential to wellbeing.", whyItMatters: "Unmasking is associated with improved mental health, authentic relationships, and reduced burnout. It also may involve grief — processing the years spent suppressing one's natural self.", commonMisconceptions: "Unmasking does not mean being rude or socially inappropriate. It means not spending energy hiding who you are. It does not require abandoning all social accommodation — it means the accommodation is voluntary rather than exhausting concealment.", relatedTerms: ["masking", "autistic-burnout", "late-diagnosis", "identity-first-language"] },
  { slug: "sensory-overload", term: "Sensory Overload", definition: "Sensory overload occurs when sensory input exceeds what the nervous system can process comfortably. Sounds, lights, smells, textures, or movement — individually or combined — can exceed the threshold and trigger distress, meltdown, or shutdown.", whyItMatters: "Sensory overload is physiological, not behavioral. The distress is real. Environments can be modified to reduce overload — this is not pampering, it is access.", commonMisconceptions: "Sensory overload is not the same as being startled. It is not an overreaction. The same environment that is merely loud for a non-autistic person may be physically painful for an autistic person.", relatedTerms: ["meltdown", "shutdown", "sensory-processing", "sensory-diet"] },
  { slug: "sensory-processing", term: "Sensory Processing", definition: "Sensory processing refers to how the nervous system receives, interprets, and responds to sensory input from the eight sensory systems: sight, sound, touch, smell, taste, proprioception, vestibular, and interoception.", whyItMatters: "Differences in sensory processing are a diagnostic criterion for autism. Understanding a person's sensory profile is essential to creating environments where they can function, learn, and thrive.", commonMisconceptions: "Sensory differences are not preferences. An autistic person who cannot tolerate a certain texture is not being picky. The experience is neurological, not volitional.", relatedTerms: ["sensory-overload", "sensory-diet", "proprioception", "interoception", "vestibular-processing"] },
  { slug: "proprioception", term: "Proprioception", definition: "Proprioception is the sensory system that tells the brain where the body is in space — the position and movement of limbs and muscles. It is sometimes called the 'hidden sense' because it operates without external input.", whyItMatters: "Many autistic people have proprioceptive differences — they may seek intense physical input (crashing, jumping, squeezing) or have difficulty with fine motor tasks. Understanding this informs appropriate sensory strategies.", commonMisconceptions: "Seeking proprioceptive input is not aggression or hyperactivity. A child who crashes into furniture may be regulating their proprioceptive system. This is a sensory need, not a behavior problem.", relatedTerms: ["sensory-processing", "vestibular-processing", "interoception", "sensory-diet"] },
  { slug: "interoception", term: "Interoception", definition: "Interoception is the internal sense that monitors the body's internal state: hunger, thirst, pain, heartbeat, bladder fullness, temperature, and emotions as physical sensations. It is increasingly recognized as a critical sensory system in autism.", whyItMatters: "Interoceptive differences explain why many autistic people struggle to identify hunger, pain, or emotions in real time. This affects self-care, emotional regulation, and health outcomes.", commonMisconceptions: "A child who does not notice they are hungry or hurt is not being dramatic or performative. Their interoceptive system may not be delivering reliable signals. This is a real neurological difference, not inattention.", relatedTerms: ["sensory-processing", "alexithymia", "proprioception"] },
  { slug: "vestibular-processing", term: "Vestibular Processing", definition: "The vestibular system, located in the inner ear, processes balance, spatial orientation, and movement. It tells the brain whether the body is upright, moving, or still. Vestibular processing differences are common in autism.", whyItMatters: "Vestibular differences can affect balance, coordination, and responses to movement. Some autistic people seek intense vestibular input (spinning, swinging); others are hypersensitive to movement and may experience motion sickness or balance challenges.", commonMisconceptions: "Seeking or avoiding movement is not defiance or attention-seeking. It is sensory regulation. Restricting vestibular input for a child who needs it can increase dysregulation.", relatedTerms: ["sensory-processing", "proprioception", "sensory-diet"] },
  { slug: "alexithymia", term: "Alexithymia", definition: "Alexithymia describes difficulty identifying and describing one's own emotions. People with alexithymia may not know what they are feeling, may experience emotions primarily as physical sensations, or may have a limited emotional vocabulary.", whyItMatters: "Roughly 50% of autistic people experience alexithymia. It affects emotional regulation, self-care, and relationships. It is not the same as not having emotions — it is difficulty recognizing them.", commonMisconceptions: "Alexithymia is not the same as being unemotional or lacking empathy. Many people with alexithymia feel emotions intensely but cannot label or communicate them clearly.", relatedTerms: ["interoception", "autistic-burnout", "masking"] },
  { slug: "double-empathy-problem", term: "Double Empathy Problem", definition: "The double empathy problem, theorized by Dr. Damian Milton, proposes that the social communication difficulties between autistic and non-autistic people are mutual. Non-autistic people have equal difficulty understanding autistic social cues, facial expressions, and communication styles. The 'problem' is not in autistic people — it is in the mismatch.", whyItMatters: "This reframes autism from a social deficit to a difference in social styles. Research supports it: autistic people communicate effectively with other autistic people. The breakdown occurs specifically at the autistic/non-autistic interface.", commonMisconceptions: "Autistic people do not lack empathy. Many are highly empathic. The double empathy problem explains social friction without placing the deficit exclusively in the autistic person.", relatedTerms: ["masking", "neurodiversity", "identity-first-language"] },
  { slug: "neurodiversity", term: "Neurodiversity", definition: "Neurodiversity is the concept that neurological differences — including autism, ADHD, dyslexia, dyspraxia, and others — are natural variations in the human genome rather than disorders to be corrected. The term was coined by sociologist Judy Singer in 1997.", whyItMatters: "The neurodiversity framework shapes how society, medicine, and education approach neurological differences. A neurodiversity lens emphasizes accommodation and acceptance rather than cure and normalization.", commonMisconceptions: "Neurodiversity does not mean autistic people do not struggle or do not need support. It means their struggles are partly caused by mismatch with neurotypical environments — and that those environments should adapt too.", relatedTerms: ["identity-first-language", "neurodivergent", "acceptance-vs-awareness"] },
  { slug: "neurodivergent", term: "Neurodivergent", definition: "Neurodivergent describes a person whose neurological development differs from what is considered typical. The term includes autism, ADHD, dyslexia, dyspraxia, OCD, Tourette syndrome, and other neurological variations.", whyItMatters: "Neurodivergent is an identity term adopted by many people who experience the world differently. It situates neurological differences within human diversity rather than medical pathology.", commonMisconceptions: "Neurodivergent is not a diagnosis. It is an identity and community term. Not everyone who qualifies medically identifies with it — and that is valid too.", relatedTerms: ["neurodiversity", "neurotypical", "allistic", "identity-first-language"] },
  { slug: "neurotypical", term: "Neurotypical", definition: "Neurotypical describes a person whose neurological development follows the typical developmental trajectory — without autism, ADHD, or other significant neurological differences. The term emerged from autistic community writing to name what had previously been assumed as the default.", whyItMatters: "Naming neurotypicality allows the autistic and neurodivergent communities to describe social expectations and systems designed for a specific neurotype without treating that neurotype as the only valid one.", commonMisconceptions: "Neurotypical does not mean normal in a value-laden sense. It is a descriptor, not a superlative. Neurotypical people have their own challenges and blind spots — including difficulty understanding neurodivergent people.", relatedTerms: ["neurodiversity", "neurodivergent", "allistic"] },
  { slug: "allistic", term: "Allistic", definition: "Allistic is a term used to describe people who are not autistic — a more specific term than neurotypical, which includes people who are neurodivergent in other ways. 'Allistic' came from autistic community writing as a parallel to 'autistic.'", whyItMatters: "Having precise language allows clearer communication. Allistic specifically describes the autistic/non-autistic distinction, while neurotypical describes the broader neurodivergent/neurotypical distinction.", commonMisconceptions: "Allistic is not a slur or insult. It is a neutral descriptor created by autistic people to name the other end of a spectrum they were already named on.", relatedTerms: ["neurotypical", "neurodivergent", "neurodiversity"] },
  { slug: "identity-first-language", term: "Identity-First Language", definition: "Identity-first language places the identity word first: 'autistic person' rather than 'person with autism.' It reflects the view that autism is a core part of who someone is — not an add-on separate from their identity.", whyItMatters: "Most autistic adults who have stated a preference prefer identity-first language. The Autistic Self Advocacy Network (ASAN) and most autistic-led organizations use identity-first language.", commonMisconceptions: "Identity-first language is not insensitive. Many autistic people find person-first language condescending — as if autism is something shameful to be distanced from. The individual's preference always takes priority.", relatedTerms: ["person-first-language", "neurodiversity", "self-advocacy"] },
  { slug: "person-first-language", term: "Person-First Language", definition: "Person-first language places the person before the identity: 'person with autism' rather than 'autistic person.' It was developed by disability advocates to emphasize the humanity of people with disabilities beyond their diagnosis.", whyItMatters: "Some parents, professionals, and individuals with intellectual disabilities prefer person-first language. In many medical and educational settings, it remains standard practice.", commonMisconceptions: "Person-first language is not universally preferred by autistic people — in fact, most autistic adults who have expressed a preference choose identity-first language. Neither is universally correct. Follow the individual's stated preference.", relatedTerms: ["identity-first-language", "neurodiversity", "self-advocacy"] },
  { slug: "executive-function", term: "Executive Function", definition: "Executive functions are the cognitive processes that support planning, organizing, initiating tasks, managing time, regulating emotions, and adapting to changing demands. Executive function challenges are common in autism and ADHD.", whyItMatters: "Executive function difficulties can look like laziness, defiance, or poor motivation from the outside — when they actually reflect genuine neurological challenges with organization and initiation.", commonMisconceptions: "Executive function is not about intelligence or effort. A highly intelligent autistic person may have significant executive function challenges. 'Just try harder' does not address an executive function difference.", relatedTerms: ["executive-dysfunction", "working-memory", "adhd", "transition-planning"] },
  { slug: "executive-dysfunction", term: "Executive Dysfunction", definition: "Executive dysfunction refers to difficulty with the cognitive processes involved in planning, initiating, organizing, and completing tasks. It affects time management, transitions, starting tasks, and managing multiple steps.", whyItMatters: "Executive dysfunction is one of the most disabling aspects of autism and ADHD in daily life. It affects school, work, and self-care in ways that are often invisible to others.", commonMisconceptions: "Executive dysfunction is not procrastination or laziness. A person can want to do a task, understand how to do it, and still be unable to start it due to executive dysfunction. This is neurological, not motivational.", relatedTerms: ["executive-function", "working-memory", "adhd"] },
  { slug: "working-memory", term: "Working Memory", definition: "Working memory is the ability to hold information in mind while using it — like following multi-step directions, keeping a train of thought, or tracking where you are in a sequence. Working memory challenges are common in autism and ADHD.", whyItMatters: "Working memory affects academic performance, daily functioning, and the ability to follow instructions. Accommodations like written instructions and visual supports can compensate significantly.", commonMisconceptions: "Working memory difficulty does not indicate low intelligence. A person with an exceptional long-term memory may have significant working memory limitations. These are distinct systems.", relatedTerms: ["executive-function", "executive-dysfunction", "visual-schedule"] },
  { slug: "sensory-diet", term: "Sensory Diet", definition: "A sensory diet is a personalized plan of sensory activities designed to help a person maintain optimal arousal and regulation throughout the day. Developed by occupational therapists, it includes specific sensory inputs at specific times.", whyItMatters: "A well-designed sensory diet can significantly reduce meltdowns, improve attention, and support daily functioning by proactively meeting sensory needs rather than reacting to dysregulation.", commonMisconceptions: "A sensory diet is not about food. The 'diet' metaphor refers to regularly scheduled sensory input — just as a nutritional diet provides regular nutrient input. It requires individualization based on the person's specific sensory profile.", relatedTerms: ["sensory-processing", "sensory-overload", "proprioception"] },
  { slug: "aac", term: "AAC (Augmentative and Alternative Communication)", definition: "AAC refers to any method of communication used to supplement or replace natural speech. It ranges from low-tech (picture boards, PECS, sign language) to high-tech (speech-generating devices and apps like Proloquo2Go, TouchChat, and Snap Core First).", whyItMatters: "AAC is not a last resort. It supports communication for nonspeaking and minimally speaking autistic people and those who are beginning communicators. Research consistently shows that AAC supports — not hinders — speech development.", commonMisconceptions: "Using AAC does not prevent speech from developing. Autistic people who use AAC have the right to communicate however works for them. AAC is a legitimate communication system, not a consolation prize.", relatedTerms: ["nonspeaking", "minimally-speaking", "presuming-competence", "pecs", "lamp"] },
  { slug: "iep", term: "IEP (Individualized Education Program)", definition: "An IEP is a legally binding document developed for students with disabilities in the US under the Individuals with Disabilities Education Act (IDEA). It outlines a student's current performance, annual goals, services, accommodations, and placement.", whyItMatters: "The IEP is the cornerstone of special education services. Understanding it — and your rights in the process — is essential for ensuring your child receives appropriate support.", commonMisconceptions: "The IEP is not just paperwork. It is a legal contract. Schools must implement what the IEP says. Parents have the right to participate, disagree, and appeal.", relatedTerms: ["fape", "lre", "idea-act", "section-504", "transition-planning"] },
  { slug: "fape", term: "FAPE (Free Appropriate Public Education)", definition: "FAPE is a right guaranteed under IDEA to all students with disabilities in the US. Schools must provide an education that is free, designed to meet the student's unique needs, and reasonably calculated to enable educational progress.", whyItMatters: "FAPE is the legal foundation of special education. When schools fail to provide it, parents have legal recourse including due process. Understanding FAPE gives families the language to advocate effectively.", commonMisconceptions: "FAPE does not mean the best possible education — courts have established it as 'more than de minimis' progress. Advocates continue to push for higher standards. It also does not mean educating a student in a certain setting — placement is a separate question (LRE).", relatedTerms: ["iep", "lre", "idea-act", "section-504"] },
  { slug: "lre", term: "LRE (Least Restrictive Environment)", definition: "LRE is the IDEA requirement that students with disabilities be educated alongside non-disabled students to the maximum extent appropriate. Removal to separate settings is allowed only when the disability is too severe for general education to be effective even with supports.", whyItMatters: "LRE is frequently misapplied. Schools sometimes place students in restrictive settings by default rather than attempting inclusion with appropriate supports. Parents can challenge restrictive placements.", commonMisconceptions: "LRE does not mean every child must be in a general education classroom at all times. It means the most integrated setting that is appropriate for that child. LRE is different for every student.", relatedTerms: ["fape", "iep", "idea-act", "section-504"] },
  { slug: "idea-act", term: "IDEA (Individuals with Disabilities Education Act)", definition: "IDEA is the federal law that governs special education in the United States. It guarantees eligible children with disabilities the right to FAPE, an IEP, and education in the LRE. It covers children from birth through age 21.", whyItMatters: "IDEA establishes the rights that families rely on for appropriate educational support. Understanding it gives families legal standing to advocate for their children.", commonMisconceptions: "IDEA does not apply to colleges and universities. Post-secondary rights for students with disabilities fall under Section 504 of the Rehabilitation Act and the Americans with Disabilities Act.", relatedTerms: ["iep", "fape", "lre", "section-504"] },
  { slug: "section-504", term: "Section 504 Plan", definition: "A Section 504 plan is an accommodation plan for students with disabilities under Section 504 of the Rehabilitation Act. Unlike an IEP, it does not provide specialized instruction — it provides accommodations to allow access to general education.", whyItMatters: "Some autistic students who do not qualify for an IEP qualify for a 504 plan. A 504 may provide extended time, preferential seating, sensory accommodations, and other supports without requiring specialized instruction.", commonMisconceptions: "A 504 plan is not a lesser IEP. It is a different tool for a different need. For students who do not need specialized instruction but do need accommodations, a 504 can provide meaningful support.", relatedTerms: ["iep", "fape", "lre", "idea-act"] },
  { slug: "aba-therapy", term: "ABA (Applied Behavior Analysis)", definition: "ABA is a behavioral therapy based on the science of behavior and learning. It is the most researched autism intervention and the most controversial in the autistic community. Modern ABA exists on a spectrum from highly structured compliance-based approaches to naturalistic, play-based approaches.", whyItMatters: "ABA shapes the therapy landscape for autistic children significantly. Understanding the range of approaches — and the autistic community's concerns — helps families make informed decisions.", commonMisconceptions: "ABA is not a single therapy. It ranges from discrete trial training (compliance-focused, often criticized) to naturalistic developmental behavioral interventions (NDBI, less controversial). The goal — what the therapy tries to change — matters enormously.", relatedTerms: ["bcba", "discrete-trial-training", "floortime"] },
  { slug: "bcba", term: "BCBA (Board Certified Behavior Analyst)", definition: "A BCBA is a professional certified by the Behavior Analyst Certification Board (BACB) to practice applied behavior analysis. BCBAs design, supervise, and evaluate ABA programs.", whyItMatters: "BCBAs are the primary providers of ABA therapy for autistic children. The quality and approach vary enormously between practitioners. Knowing what questions to ask helps families evaluate whether a given BCBA's approach aligns with their values.", commonMisconceptions: "BCBA certification does not indicate a particular therapeutic philosophy. BCBAs range from compliance-focused to neurodiversity-affirming in their approaches.", relatedTerms: ["aba-therapy", "discrete-trial-training"] },
  { slug: "discrete-trial-training", term: "Discrete Trial Training (DTT)", definition: "Discrete trial training is a structured ABA teaching method using repeated, discrete trials: a therapist presents a cue, the child responds, and the therapist provides a consequence (reinforcement or correction). It is highly structured and repetitive.", whyItMatters: "DTT has been used to teach specific skills but has faced criticism from autistic advocates for its focus on compliance and its history of suppressing autistic behaviors. It is one type of ABA — not synonymous with ABA as a whole.", commonMisconceptions: "DTT is not the only ABA approach. Many practitioners have moved toward naturalistic methods. The appropriateness of DTT depends heavily on the goals — teaching toileting is different from training away stimming.", relatedTerms: ["aba-therapy", "bcba", "floortime"] },
  { slug: "floortime", term: "Floortime (DIR/Floortime)", definition: "Floortime, developed by Dr. Stanley Greenspan, is a developmental therapy model that follows the child's lead, entering their world at their level and building on their natural interests to support emotional and social development.", whyItMatters: "Floortime is generally considered more aligned with neurodiversity values than compliance-based ABA. It prioritizes relationship, engagement, and emotional development rather than behavior compliance.", commonMisconceptions: "Floortime is not the absence of structure. It has a developmental framework (DIR — Developmental, Individual-difference, Relationship-based). The 'floor' refers to getting down to the child's level — physical and developmental.", relatedTerms: ["aba-therapy", "discrete-trial-training"] },
  { slug: "pecs", term: "PECS (Picture Exchange Communication System)", definition: "PECS is a communication system that teaches non-speaking individuals to communicate by exchanging picture cards. It follows a structured training protocol and is commonly used in early intervention.", whyItMatters: "PECS can support initial communication for non-speaking autistic children and is used as a bridge to more robust AAC systems.", commonMisconceptions: "PECS is sometimes mistakenly seen as a ceiling for communication. It is one tool among many. Many children who begin with PECS move on to robust speech-generating devices and develop stronger communication over time.", relatedTerms: ["aac", "lamp", "makaton", "augmentative-communication"] },
  { slug: "lamp", term: "LAMP (Language Acquisition through Motor Planning)", definition: "LAMP is an AAC approach that uses consistent motor patterns to build language. Based on principles of motor learning, it teaches communication through consistent, repeated movements on an AAC device to support automaticity.", whyItMatters: "LAMP has shown strong results for children with significant motor planning challenges, including those with apraxia of speech. It is particularly effective when other AAC approaches have not produced progress.", commonMisconceptions: "LAMP is a specific approach within AAC — not a device or a system. It can be implemented with various AAC tools. Its success requires trained implementers who can model consistently.", relatedTerms: ["aac", "pecs", "augmentative-communication", "apraxia"] },
  { slug: "makaton", term: "Makaton", definition: "Makaton is a language program using signs, symbols, and speech to support communication. It uses a core vocabulary of signs, often alongside spoken words, and is widely used in the UK and internationally.", whyItMatters: "Makaton supports communication for people with a wide range of communication needs. It is particularly useful when fine motor challenges limit the use of other AAC systems.", commonMisconceptions: "Makaton is not the same as British Sign Language (BSL). It uses some BSL signs but is a distinct system designed for communication support rather than as a complete language.", relatedTerms: ["aac", "pecs", "lamp", "augmentative-communication"] },
  { slug: "augmentative-communication", term: "Augmentative Communication", definition: "Augmentative communication refers to any approach that supplements existing communication abilities. It encompasses the full range of AAC — from gestures and picture boards to sophisticated speech-generating devices — used alongside whatever natural communication is present.", whyItMatters: "Augmentative communication affirms that communication exists on a continuum. Adding AAC to someone's communication repertoire does not replace what is already there — it adds to it.", commonMisconceptions: "Augmentative communication is not a sign of failure. It is a recognition that communication needs support — just as glasses augment vision without replacing it.", relatedTerms: ["aac", "pecs", "lamp", "nonspeaking"] },
  { slug: "nonspeaking", term: "Nonspeaking", definition: "Nonspeaking describes autistic and disabled people who do not use spoken speech as their primary communication method. It is preferred over the older term 'nonverbal' by many autistic advocates, as these individuals often have robust language — they simply do not speak.", whyItMatters: "The language of 'nonverbal' implied an absence of language that is often inaccurate. Many nonspeaking autistic people communicate in writing, via AAC, or through other means with sophisticated language.", commonMisconceptions: "Nonspeaking does not mean non-communicating. It does not mean non-intelligent. Presuming competence — assuming ability — is the correct starting position.", relatedTerms: ["minimally-speaking", "aac", "presuming-competence"] },
  { slug: "minimally-speaking", term: "Minimally Speaking", definition: "Minimally speaking (also 'minimally verbal') describes people who use speech functionally but with significant limitations — fewer than 30 functional words or phrases. It is used in research and clinical contexts to identify a subgroup with specific communication support needs.", whyItMatters: "Distinguishing minimally speaking from nonspeaking and fully verbal autism helps tailor communication supports. Many minimally speaking individuals make significant communication gains with appropriate AAC and support.", commonMisconceptions: "Minimally speaking is not a permanent category. Many people who are minimally speaking in childhood develop more robust communication — verbal, AAC, or both — with appropriate support.", relatedTerms: ["nonspeaking", "aac", "presuming-competence"] },
  { slug: "presuming-competence", term: "Presuming Competence", definition: "Presuming competence means assuming that every person — regardless of communication, motor, or cognitive challenges — has the capacity to learn, communicate, and contribute, until evidence demonstrates otherwise. It means giving the benefit of the doubt.", whyItMatters: "When competence is not presumed, people receive watered-down education, limited opportunities, and inadequate communication systems. When it is presumed, people often exceed expectations dramatically.", commonMisconceptions: "Presuming competence is not naive optimism. It is the ethical default — the same presumption extended to anyone whose ability has not been assessed. The burden of proof should be on demonstrated limitation, not assumed limitation.", relatedTerms: ["nonspeaking", "aac", "identity-first-language", "self-advocacy"] },
  { slug: "late-diagnosis", term: "Late Diagnosis", definition: "Late diagnosis refers to receiving an autism diagnosis in adulthood or significantly later than is typical. It is increasingly recognized as common — particularly for women, girls, people of color, and those who masked effectively throughout childhood.", whyItMatters: "Late diagnosis can bring relief, clarity, grief, and a need to reinterpret one's life history. It is valid and meaningful at any age. Access to diagnosis remains unequal — systemic barriers affect who gets diagnosed early.", commonMisconceptions: "Late-diagnosed autistic people are just as autistic as those diagnosed in childhood. Autism does not begin at diagnosis. Late diagnosis is often accompanied by mental health impacts from years of misdiagnosis or no diagnosis.", relatedTerms: ["masking", "camouflaging", "unmasking", "identity-first-language"] },
  { slug: "high-masking", term: "High-Masking", definition: "High-masking describes autistic people who are particularly skilled at concealing autistic traits in social situations. High-masking individuals often receive later diagnoses, are more likely to be female or gender-diverse, and are at higher risk of burnout.", whyItMatters: "High-masking autism is frequently undetected by diagnostic tools calibrated to recognize more visible presentations. High-maskers are often told they 'don't look autistic' — which reflects the diagnostic tools' limitations, not their experience.", commonMisconceptions: "High-masking does not mean mild autism. The energy spent masking is invisible to observers but profoundly costly. 'High-functioning' language often masks (pun intended) significant support needs.", relatedTerms: ["masking", "camouflaging", "late-diagnosis", "autistic-burnout"] },
  { slug: "camouflaging", term: "Camouflaging", definition: "Camouflaging is the broader term for hiding neurodivergent characteristics in social contexts. It encompasses masking, compensation (developing alternative strategies), and assimilation (adopting neurotypical behaviors). It is most studied in autistic women and girls.", whyItMatters: "Research by Dr. Laura Hull and colleagues has documented camouflaging systematically. It is linked to later diagnosis, higher rates of anxiety and depression, and significant wellbeing impacts.", commonMisconceptions: "Camouflaging is not the same as social skill development. Developing a genuine skill is different from suppressing your natural way of being to appear neurotypical.", relatedTerms: ["masking", "high-masking", "late-diagnosis", "autistic-burnout"] },
  { slug: "twice-exceptional", term: "Twice-Exceptional (2e)", definition: "Twice-exceptional describes students who have both a disability (such as autism, ADHD, or dyslexia) and giftedness. These students have advanced abilities in some areas and significant support needs in others — a combination that is frequently misunderstood.", whyItMatters: "Twice-exceptional students are often underserved because their giftedness masks their disability or vice versa. They may be bored, frustrated, and failing simultaneously — and neither their giftedness nor their disability is being addressed.", commonMisconceptions: "Being twice-exceptional does not mean the challenges are less real because of the gifts. Advanced ability in one area does not compensate for genuine difficulty in another.", relatedTerms: ["spiky-profile", "executive-dysfunction", "iep"] },
  { slug: "spiky-profile", term: "Spiky Profile", definition: "A spiky profile describes the pattern of significant strengths and significant challenges that characterize many autistic people. Unlike an average profile that is relatively uniform across domains, a spiky profile shows dramatic peaks and valleys.", whyItMatters: "Understanding a spiky profile helps families and educators set appropriate expectations — high expectations in areas of strength, genuine support in areas of challenge, without using one to dismiss the other.", commonMisconceptions: "A spiky profile is not inconsistency or laziness. Someone who excels at math but cannot organize their backpack is not 'choosing' to fail at one and succeed at the other. Both are real.", relatedTerms: ["twice-exceptional", "executive-dysfunction", "special-interest"] },
  { slug: "transition-planning", term: "Transition Planning", definition: "Transition planning is the process of preparing autistic and disabled students for life after high school — including post-secondary education, employment, independent living, and community participation. Under IDEA, it must begin by age 16 (and often should begin earlier).", whyItMatters: "Transition planning is one of the most neglected areas in special education. Adult services and supports are dramatically underfunded. Early planning significantly improves outcomes.", commonMisconceptions: "Transition planning is not a one-time meeting. It is an ongoing process that should involve the student's own voice, goals, and preferences — not just professional decisions about what is 'realistic.'", relatedTerms: ["iep", "fape", "adults", "self-advocacy"] },
  { slug: "functional-behavioral-assessment", term: "Functional Behavioral Assessment (FBA)", definition: "An FBA is a systematic process for identifying the function — the 'why' — of a specific behavior. Understanding what need a behavior meets allows for the development of supports that address that need more effectively.", whyItMatters: "Addressing the function of a behavior (communication, sensory regulation, escape, attention) leads to lasting change. Punishing behavior without understanding its function is likely to fail or displace the behavior to something else.", commonMisconceptions: "An FBA is not about proving a child is misbehaving. It is about understanding what need they are meeting and finding better ways to meet it. It should lead to support, not punishment.", relatedTerms: ["behavior-intervention-plan", "aba-therapy", "executive-dysfunction"] },
  { slug: "behavior-intervention-plan", term: "Behavior Intervention Plan (BIP)", definition: "A BIP is a plan based on an FBA that identifies strategies for teaching alternative behaviors and modifying the environment to reduce challenging behaviors. It should include proactive strategies, not just reactive consequences.", whyItMatters: "A well-designed BIP addresses the function of behavior rather than just trying to suppress it. It includes positive supports, environmental modifications, and skill-building.", commonMisconceptions: "A BIP is not a punishment plan. It is a support plan. Effective BIPs teach replacement behaviors and reduce environmental demands that trigger the behavior.", relatedTerms: ["functional-behavioral-assessment", "aba-therapy", "iep"] },
  { slug: "social-stories", term: "Social Stories", definition: "Social Stories, developed by Carol Gray, are short narratives that describe social situations, events, or concepts in a structured format designed to help autistic people understand social expectations and contexts.", whyItMatters: "Social Stories can help autistic people prepare for new situations, understand others' perspectives, and navigate social expectations that are not intuitive. They are most effective when tailored to the individual.", commonMisconceptions: "Social Stories are not about making autistic people conform to neurotypical norms. At their best, they help autistic people understand situations so they can make their own informed decisions.", relatedTerms: ["visual-schedule", "transition-planning", "scripts"] },
  { slug: "visual-schedule", term: "Visual Schedule", definition: "A visual schedule is a visual representation of the sequence of activities in a day or during a specific routine. It uses pictures, icons, or words to make time and transitions predictable and understandable.", whyItMatters: "Visual schedules reduce anxiety about transitions and unexpected changes by making time concrete and predictable. They support executive function and independence.", commonMisconceptions: "Visual schedules are not just for young children or those with significant support needs. Many autistic adults use visual and written schedules to support executive function and reduce anxiety.", relatedTerms: ["social-stories", "executive-function", "transition-planning"] },
  { slug: "demand-avoidance", term: "Demand Avoidance", definition: "Demand avoidance describes a behavioral pattern in which a person resists and avoids ordinary demands and expectations. In autism, it is associated with PDA (Pathological Demand Avoidance) — an anxiety-driven profile.", whyItMatters: "Understanding demand avoidance as anxiety-driven — rather than oppositional — changes the response. Collaborative, low-demand approaches are more effective than increased demands or consequences.", commonMisconceptions: "Demand avoidance is not defiance or manipulation. It is an anxiety response. The nervous system perceives demands as threats. Traditional behavioral approaches often increase anxiety and resistance.", relatedTerms: ["pda", "anxiety-disorder", "executive-dysfunction"] },
  { slug: "pda", term: "PDA (Pathological Demand Avoidance)", definition: "PDA is an autism profile characterized by extreme anxiety-driven avoidance of everyday demands and expectations. People with PDA may use social strategies (negotiating, making excuses, distracting) to avoid demands, and often present very differently from stereotypical autism presentations.", whyItMatters: "PDA is widely recognized in the UK and growing in awareness in the US. It requires a fundamentally different approach from typical autism support strategies. Low-demand, collaborative, autonomy-supportive approaches are most effective.", commonMisconceptions: "PDA is not the same as oppositional defiant disorder (ODD). It is driven by anxiety rather than defiance. The goal is not to force compliance but to build a relationship of trust and reduce anxiety.", relatedTerms: ["demand-avoidance", "anxiety-disorder", "masking", "autistic-burnout"] },
  { slug: "apraxia", term: "Apraxia of Speech", definition: "Apraxia of speech is a motor speech disorder affecting the planning and programming of the movements needed for speech. It is distinct from aphasia (language disorder) — the person knows what they want to say but has difficulty translating that into movement.", whyItMatters: "Apraxia is frequently co-occurring with autism and significantly affects communication. Appropriate support (including AAC) is essential. Apraxia does not indicate intellectual disability.", commonMisconceptions: "Apraxia is not laziness or lack of effort. The motor planning required for speech is simply not working reliably. More effort does not fix a motor planning disorder.", relatedTerms: ["aac", "lamp", "nonspeaking"] },
  { slug: "dyspraxia", term: "Dyspraxia (DCD)", definition: "Dyspraxia, now more commonly called Developmental Coordination Disorder (DCD), affects the planning and execution of physical movements. It affects fine motor skills, gross motor skills, and coordination.", whyItMatters: "Dyspraxia is common in autism and can affect handwriting, sports, daily self-care, and social confidence. Occupational therapy significantly supports people with dyspraxia.", commonMisconceptions: "Dyspraxia is not clumsiness that will be grown out of. It is a genuine neurodevelopmental condition. With the right support, people with dyspraxia develop effective strategies for managing their challenges.", relatedTerms: ["proprioception", "sensory-processing", "executive-function"] },
  { slug: "hypermobility", term: "Hypermobility", definition: "Hypermobility refers to joints that move beyond the typical range of motion. Hypermobile Ehlers-Danlos Syndrome (hEDS) and Hypermobility Spectrum Disorders (HSD) are chronic connective tissue conditions significantly over-represented in the autistic population.", whyItMatters: "The autism-hypermobility connection is an area of growing research. Hypermobility affects pain, fatigue, proprioception, and quality of life. It is frequently undiagnosed in autistic people whose communication differences make pain reporting difficult.", commonMisconceptions: "Being able to do splits or bend fingers back is not just a party trick in the context of hypermobility disorders. Chronic pain, fatigue, and joint instability are real and often disabling consequences.", relatedTerms: ["proprioception", "co-occurring-conditions", "interoception"] },
  { slug: "sensory-seeking", term: "Sensory Seeking", definition: "Sensory seeking describes a pattern in which a person actively seeks out sensory input — crashing into things, touching textures, seeking intense movement, making loud sounds, or seeking strong flavors and smells.", whyItMatters: "Sensory seeking meets a real neurological need. Providing appropriate sensory input through a planned sensory diet reduces the need to seek it in less appropriate ways.", commonMisconceptions: "Sensory seeking is not aggression or hyperactivity, though it can look similar. It is the nervous system requesting input it needs for regulation.", relatedTerms: ["sensory-avoiding", "sensory-processing", "sensory-diet"] },
  { slug: "sensory-avoiding", term: "Sensory Avoiding", definition: "Sensory avoiding describes a pattern in which a person actively avoids sensory input — pulling away from touch, covering ears, avoiding crowds, refusing certain textures, or withdrawing from strong smells.", whyItMatters: "Sensory avoidance reflects genuine neurological sensitivity, not preference or picky behavior. Forcing sensory input on a sensory-avoiding person can cause significant distress and dysregulation.", commonMisconceptions: "Sensory avoidance is not stubbornness or poor tolerance. The input is genuinely aversive at a neurological level — comparable to asking a non-autistic person to put their hand on a hot stove.", relatedTerms: ["sensory-seeking", "sensory-processing", "sensory-overload"] },
  { slug: "fawn-response", term: "Fawn Response", definition: "The fawn response is a trauma-informed concept describing a stress response in which a person appeases others to avoid conflict or danger. It extends the traditional fight-flight-freeze model. In the context of autism and PDA, fawning may manifest as extreme compliance under pressure.", whyItMatters: "Understanding the fawn response helps explain why some autistic people appear to comply outwardly while experiencing significant internal distress. Outward compliance is not the same as wellbeing.", commonMisconceptions: "Fawning is not politeness or good behavior. It is a stress response. A child who always says yes and never complains may be fawning rather than content.", relatedTerms: ["pda", "masking", "autistic-burnout"] },
  { slug: "rejection-sensitive-dysphoria", term: "Rejection Sensitive Dysphoria (RSD)", definition: "RSD is an intense emotional response to perceived rejection, criticism, failure, or teasing. It is common in ADHD and increasingly recognized in autistic people. The emotional pain of RSD is described as overwhelming and out of proportion by those experiencing it.", whyItMatters: "RSD affects relationships, school, and work significantly. Understanding it helps separate the emotional intensity from the trigger — the emotional response is neurological, not character.", commonMisconceptions: "RSD is not oversensitivity or immaturity. The emotional pain is physiologically real and intense. 'Just toughen up' is not a useful response to a neurological experience.", relatedTerms: ["alexithymia", "adhd", "masking", "autistic-burnout"] },
  { slug: "aphantasia", term: "Aphantasia", definition: "Aphantasia is the inability to form mental images — the mind's eye is blank. It is more common in autistic and neurodivergent people than in the general population and can affect memory, imagination, and creative processes.", whyItMatters: "Aphantasia is underrecognized and can affect how people learn, remember, and navigate certain tasks. Understanding it helps tailor support and explanation strategies.", commonMisconceptions: "Aphantasia is not a disorder requiring treatment. It is a neurological difference in how the mind processes imagery. Many people with aphantasia function without difficulty once they understand their own cognition.", relatedTerms: ["neurodivergent", "sensory-processing"] },
  { slug: "co-occurring-conditions", term: "Co-occurring Conditions", definition: "Co-occurring conditions are diagnoses that exist alongside autism. Common co-occurring conditions include ADHD, anxiety disorder, OCD, depression, epilepsy, dyspraxia, hypermobility, GI issues, sleep disorders, and ARFID.", whyItMatters: "Most autistic people have at least one co-occurring condition. Understanding these conditions separately from autism allows for targeted, appropriate support.", commonMisconceptions: "Co-occurring conditions are not symptoms of autism. They are separate diagnoses that require separate assessment and treatment, even though they frequently appear together.", relatedTerms: ["adhd", "anxiety-disorder", "epilepsy", "dyspraxia", "hypermobility"] },
  { slug: "self-advocacy", term: "Self-Advocacy", definition: "Self-advocacy is the practice of speaking up for oneself — communicating needs, rights, and preferences. In the disability context, the self-advocacy movement emerged from people with developmental disabilities demanding the right to make their own decisions.", whyItMatters: "Self-advocacy skills are essential for autistic people navigating schools, healthcare, workplaces, and social systems. Supporting self-advocacy means creating space for autistic people to communicate their own needs.", commonMisconceptions: "Self-advocacy is not rudeness or non-compliance. It is the practice of asking for what you need. Supporting self-advocacy is more important than compliance with what others think is best.", relatedTerms: ["identity-first-language", "neurodiversity", "transition-planning"] },
  { slug: "hyperlexia", term: "Hyperlexia", definition: "Hyperlexia is characterized by an advanced ability to read — significantly above what is expected for developmental age — alongside challenges with language comprehension. It is common in autism and often appears between ages 2-5.", whyItMatters: "Hyperlexia can be misread as advanced intelligence across the board. It is important to assess comprehension separately from decoding. Many hyperlexic children need specific support for understanding what they can read.", commonMisconceptions: "Hyperlexia is not the same as being gifted in reading. The gap between decoding ability and comprehension is the key feature. A child reading chapter books at age 3 who cannot follow simple verbal directions may have hyperlexia.", relatedTerms: ["twice-exceptional", "spiky-profile", "echolalia"] },
  { slug: "arfid", term: "ARFID (Avoidant/Restrictive Food Intake Disorder)", definition: "ARFID is an eating disorder characterized by avoidance or restriction of food based on sensory properties, fear of choking or vomiting, or lack of interest in eating — not body image. It is significantly more common in autistic people.", whyItMatters: "ARFID is a genuine medical and nutritional concern that deserves specialized support. Sensory-based feeding therapy is more effective than pressure-based approaches.", commonMisconceptions: "ARFID is not picky eating that will resolve with persistence. It is not willful defiance. Forcing foods to people with ARFID typically worsens the condition.", relatedTerms: ["sensory-processing", "co-occurring-conditions", "sensory-avoiding"] },
  { slug: "echopraxia", term: "Echopraxia", definition: "Echopraxia is the involuntary imitation of another person's movements or gestures. Like echolalia with speech, echopraxia involves mimicking physical actions, sometimes immediately and sometimes with delay.", whyItMatters: "Echopraxia, when present, reflects the same underlying processing pattern as echolalia. Understanding it as a feature of neurological processing rather than mockery or defiance changes how it is managed.", commonMisconceptions: "Echopraxia is not intentional mimicry or teasing. It is a neurological phenomenon. Responding with frustration or discipline is unlikely to help.", relatedTerms: ["echolalia", "scripts", "sensory-processing"] },
];
